#!/usr/bin/env python3
"""
Bug #2217: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['normalization', 'l2_normalize'], ['layout', 'resize_linear_aligncorners'], ['layout', 'transpose_transpose_squash'], ['constant', 'where_const_condition'], ['attention', 'matmul_4d_batch'], ['attention', 'matmul_4d_batch']]
Dependencies: numpy jax
Run         : python unique_2217.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex("ccbc8c2b"), dtype=np.float32).reshape([1])
_w1 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1, 1, 1, 1])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([0])
_w3 = np.frombuffer(bytes.fromhex("0000803f0000803f0000004000000040"), dtype=np.float32).reshape([4])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.int64).reshape([1, 64, 32, 32])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64, 32, 32])
_w6 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 32, 32])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 32, 32])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64, 16, 16])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_l2n2_norm = jnp.sqrt(jnp.sum(x*x, axis=(-1,), keepdims=True))
    n0_l2n2_add = n0_l2n2_norm + _w0
    n0_l2n2_div = x / n0_l2n2_add
    n0_l2n2_out = n0_l2n2_div * _w1
    n100_resi_out = (lambda _x, _sc: jnp.transpose(jax.image.resize(jnp.transpose(_x,(0,2,3,1)), (int(_x.shape[0]), int(_x.shape[2]*_sc[2]), int(_x.shape[3]*_sc[3]), int(_x.shape[1])), method='linear'), (0,3,1,2)))(n0_l2n2_out, _w3)
    n200_tts_t1 = jnp.transpose(n100_resi_out, [2, 3, 0, 1])
    n200_tts_out = jnp.transpose(n200_tts_t1, [2, 3, 0, 1])
    n300_wcc_wh = jnp.where(_w4, n200_tts_out, _w5)
    n300_wcc_out = n300_wcc_wh * n200_tts_out
    n400_mm4d_out = jnp.matmul(n300_wcc_out, _w6)
    n500_mm4d_out = jnp.matmul(n400_mm4d_out, _w7)
    return jnp.asarray(n500_mm4d_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
